import React, { useState } from 'react';
import './App.css';
import NotesSection from './components/NotesSection';
import GradingSection from './components/GradingSection';
import AssignmentsSection from './components/AssignmentsSection';
import AnnouncementsSection from './components/AnnouncementsSection';

function App() {
  const [activeTab, setActiveTab] = useState('notes');

  return (
    <div className="app">
      <header className="app-header">
        <div className="header-content">
          <h1>📚 Teacher Management System</h1>
          <p>Manage notes, grades, assignments, and announcements</p>
        </div>
      </header>

      <nav className="app-nav">
        <button 
          className={`nav-btn ${activeTab === 'notes' ? 'active' : ''}`}
          onClick={() => setActiveTab('notes')}
        >
          📝 Notes
        </button>
        <button 
          className={`nav-btn ${activeTab === 'grading' ? 'active' : ''}`}
          onClick={() => setActiveTab('grading')}
        >
          ✅ Grading
        </button>
        <button 
          className={`nav-btn ${activeTab === 'assignments' ? 'active' : ''}`}
          onClick={() => setActiveTab('assignments')}
        >
          📋 Assignments
        </button>
        <button 
          className={`nav-btn ${activeTab === 'announcements' ? 'active' : ''}`}
          onClick={() => setActiveTab('announcements')}
        >
          📢 Announcements
        </button>
      </nav>

      <main className="app-main">
        {activeTab === 'notes' && <NotesSection />}
        {activeTab === 'grading' && <GradingSection />}
        {activeTab === 'assignments' && <AssignmentsSection />}
        {activeTab === 'announcements' && <AnnouncementsSection />}
      </main>

      <footer className="app-footer">
        <p>Teacher Management System © 2024 - Connected to Backend API</p>
      </footer>
    </div>
  );
}

export default App;
